import"./hoisted.D6Vph_Vd.js";document.getElementById("quoteForm")?.addEventListener("submit",async r=>{r.preventDefault();const s=["fname","lname","email","company","role","solution"];let n=!0;if(s.forEach(e=>{const t=document.getElementById(e);t?.value||(t?.classList.add("error"),n=!1,setTimeout(()=>t?.classList.remove("error"),2500))}),!n)return;const o=document.querySelector(".submit-btn");o.textContent,o.textContent="Sending...",o.disabled=!0;try{const e=document.getElementById("quoteForm"),t=new FormData(e);if((await fetch("/",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams(t).toString()})).ok)e.style.display="none",document.getElementById("formSuccess").style.display="block";else throw new Error("Network response was not ok")}catch(e){console.error("Form submission error:",e),document.getElementById("quoteForm").style.display="none",document.getElementById("formSuccess").style.display="block"}});
